solutions.javascript:
// Solution
function mergeObjects<T, U>(a: T, b: U): T & U {
  return {
    ...Object.keys(a).filter(k => typeof a[k] === 'string').map(k => ({ [k]: a[k] })),
    ...Object.keys(b).map(k => ({ [k]: b[k] }))
  };
}

solutions.python:
class Solution:
    def mergeObjects(self, a: dict, b: dict) -> dict:
        return {**{k: v for k, v in a.items() if isinstance(v, str)}, **{k: v for k, v in b.items()}}
